                let _selfOffCpu = try ({ buf in
                let _idleNs = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _lockNs = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _semaphoreNs = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _ipcNs = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _ioReadNs = try ({ buf in try decodeVarint(from: &buf) })(&buf)
