            })(&buf)
                let _selfPetSamples = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _totalPetSamples = try ({ buf in try decodeVarint(from: &buf) })(&buf)
                let _selfOffCpuIntervals = try ({ buf in try decodeVarint(from: &buf) })(&buf)
